THE RISK:
{
 "id": "enterprise-gpu-pods-skip-pdus",
 "title": "The only growing part of the enterprise 29% ships as pre-integrated GPU racks with shelf power — the venture addresses only the shrinking remainder",
 "narrative": "seg.enterprise (0.29) looks like the conservative, PDU-sticky base: on-prem halls refreshing rack power on slow cycles. But Synergy is explicit that enterprise capacity was flat for years and is only now growing again 'thanks to GenAI applications and GPU infrastructure' — and that increment arrives as OEM-integrated GPU pods built to vendor reference designs with in-rack power shelves, not as field-installed PDUs. Meanwhile the legacy stock the PDU thesis actually addresses is the part Synergy shows declining two percentage points a year toward 19% by 2031. The model books the whole 0.29 as PDU-addressable; structurally, only the shrinking half is.",
 "category": "model-structure",
 "targetNodes": [
  "seg.enterprise"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "Synergy: after a sustained period of no growth, on-premise capacity is getting a boost from GenAI/GPU infrastructure — the enterprise segment's growth is exclusively AI-density capacity",
   "refs": [
    "digest:seg-mix#c20",
    "digest:seg-mix#c2"
   ]
  },
  {
   "step": "propagation",
   "text": "Enterprise AI capacity is procured as pre-integrated racks (vendor reference designs with busbar/power-shelf distribution) from OEMs, bypassing the discrete rack-PDU purchase entirely; the residual PDU-buying legacy stock is the component falling ~2pp/year toward 19% share by 2031",
   "refs": [
    "digest:seg-mix#c22",
    "digest:seg-mix#c5"
   ]
  },
  {
   "step": "model-impact",
   "text": "seg.enterprise 0.29 is a single-source capacity share with no sensitivityRange and no decomposition into legacy-refresh vs GPU-pod capacity; treating all of it as PDU-addressable overstates the enterprise slice a new PDU entrant can sell into during Year 1",
   "refs": [
    "ledger:seg.enterprise",
    "digest:seg-mix#c3"
   ]
  }
 ],
 "whyMissable": "The enterprise share is the model's most 'boring' number — a declining legacy segment nobody expects surprises from. The trap is that its headline share is being propped up by exactly the capacity type (GPU pods) that doesn't buy the product, so the stable-looking 0.29 conceals a faster-shrinking addressable core.",
 "expectedObviousness": "medium",
 "falsifier": "CE enterprise DC refresh data (e.g., a Vertiv/Schneider channel survey or distributor sell-through) showing intelligent rack PDUs attached to new enterprise AI/GPU deployments at rates comparable to general-purpose IT racks.",
 "likelihood": {
  "value": 0.24,
  "rationale": "Synergy's GenAI-boost claim and the 2pp/yr on-prem decline are both sourced; the open question is what fraction of CE enterprise AI capacity ships pre-integrated vs stick-built — documented for US hyperscale-adjacent deployments, thinner evidence for mid-size European enterprises. [evidence revision: The trigger (GenAI-driven enterprise growth) is confirmed, but the critical bypass mechanism is undercut: NVIDIA's flagship enterprise reference architecture explicitly ships in a traditional-rack-PDU variant (three 2U PDUs per rack), and multiple PDU market analysts attribute demand growth directly to AI/GPU density. Busbar/power-shelf pods exist but coexist with PDU-based AI racks rather than universally displacing them, weakening the claim that the whole growing increment is non-PDU-addressable. Lowered from 0.35 toward the contradicting evidence, but not to the floor since the legacy-vs-pod decomposition gap and the busbar option remain real.]",
  "basis": "evidence",
  "revisedFrom": 0.35
 },
 "perturbation": [
  {
   "nodeId": "seg.enterprise",
   "op": "set",
   "value": 0.21,
   "note": "GPU-pod increment (~1/4 of the enterprise slice) carries no discrete PDU content; legacy refresh continues its documented decline"
  }
 ],
 "indicators": [
  {
   "signal": "Form factor of enterprise AI infrastructure orders (integrated rack-scale systems vs component builds)",
   "where": "Dell/HPE/Lenovo quarterly earnings — AI server segment commentary on rack-scale vs unit shipments; NVIDIA reference-design partner announcements",
   "threshold": "Rack-scale integrated systems exceeding ~50% of enterprise AI infrastructure revenue mix",
   "updates": "increases"
  },
  {
   "signal": "PDU attach rate in CE enterprise channel sell-through",
   "where": "CE IT distribution (also/ALSO, Ingram Micro) product-category reporting; Schneider/Vertiv earnings commentary on enterprise vs cloud PDU demand",
   "threshold": "Enterprise PDU line flat-to-down while enterprise AI server line grows double-digit",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Commission a decomposition of CE enterprise capacity additions into legacy-refresh vs pre-integrated AI-pod capacity (analyst inquiry with Synergy/Omdia plus 5 CIO interviews)",
   "type": "information",
   "voiNodeId": "seg.enterprise",
   "note": "Splits the 0.29 into PDU-addressable and non-addressable components"
  },
  {
   "action": "Target the enterprise refresh cycle explicitly (retrofit-friendly form factors, drop-in replacement for installed Schneider/Vertiv units) rather than new-build AI capacity",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Aligns Year-1 pipeline with the segment component that verifiably buys PDUs"
  }
 ],
 "evidenceStatus": "contested",
 "evidence": [
  {
   "title": "DGX SuperPOD B300 AC Power Reference Architecture",
   "sourceType": "industry-report",
   "publisher": "NVIDIA",
   "date": "2025-10-30",
   "excerpt": "This Reference Architecture is focused on traditional PDU and AC powered EIA racks... Figure 2 shows 72 x NVIDIA DGX B300 PS systems in standard racks each with three (3) 2U rack PDUs for maximum redundancy. DGX SuperPOD with DGX B300 systems is also available for more dense DB Busbar solutions as well.",
   "url": "https://docs.nvidia.com/dgx-superpod/reference-architecture/scalable-infrastructure-b300-xdr/latest/dgx-superpod-architecture.html",
   "attached": true
  },
  {
   "title": "The World's Total Data Center Capacity is Shifting Rapidly to Hyperscale Operators",
   "sourceType": "industry-report",
   "publisher": "Synergy Research Group",
   "date": "2025-06-24",
   "excerpt": "After a sustained period of essentially no growth, on-premise data center capacity is receiving something of a boost thanks to GenAI applications and GPU infrastructure. Nonetheless, on-premise share of the total will drop.",
   "url": "https://www.srgresearch.com/articles/the-worlds-total-data-center-capacity-is-shifting-rapidly-to-hyperscale-operators",
   "attached": true
  },
  {
   "title": "Data Center Rack PDU Market Report 2033",
   "sourceType": "analyst-estimate",
   "publisher": "Grand View Research",
   "date": null,
   "excerpt": "The growth of high-performance computing (HPC), artificial intelligence (AI), and GPU-intensive workloads is driving demand for data center rack power distribution unit market.",
   "url": "https://www.grandviewresearch.com/industry-analysis/data-center-rack-power-distribution-unit-pdu-market",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.srgresearch.com/articles/the-worlds-total-data-center-capacity-is-shifting-rapidly-to-hyperscale-operators",
   "stance": "supports",
   "quote": "After a sustained period of essentially no growth, on-premise data center capacity is receiving something of a boost thanks to GenAI applications and GPU infrastructure. Nonetheless, on-premise share of the total will dro"
  },
  {
   "url": "https://www.ciodive.com/news/cloud-enterprise-data-center-infrastructure-spend-generative-ai/737049/",
   "stance": "supports",
   "quote": "Enterprise spending on data center gear increased 21% after five years of marginal growth, thanks largely to generative AI, according to SRG."
  },
  {
   "url": "https://docs.nvidia.com/dgx-superpod/reference-architecture/scalable-infrastructure-b300-xdr/latest/dgx-superpod-architecture.html",
   "stance": "contradicts",
   "quote": "This Reference Architecture is focused on traditional PDU and AC powered EIA racks. DGX SuperPOD with DGX B300 systems is also available for more dense DB Busbar solutions as well.\n\nFigure 2 shows 72 x NVIDIA DGX B300 PS systems in standard racks each with three (3) 2U rack PDUs for maximum redundancy."
  },
  {
   "url": "https://www.grandviewresearch.com/industry-analysis/data-center-rack-power-distribution-unit-pdu-market",
   "stance": "contradicts",
   "quote": "The growth of high-performance computing (HPC), artificial intelligence (AI), and GPU-intensive workloads is driving demand for data center rack power distribution unit market."
  },
  {
   "url": "https://www.vertiv.com/en-us/about/news-and-events/corporate-news/vertiv-expands-rack-pdu-portfolio-for-high-density-computing-applications-for-ai-and-hpc-deployments-in-north-america-and-emea/",
   "stance": "contradicts",
   "quote": "Vertiv expands rack PDU portfolio for high-density computing applications for AI and HPC deployments in North America and EMEA"
  },
  {
   "url": "https://www.mordorintelligence.com/industry-reports/intelligent-pdu-market",
   "stance": "contradicts",
   "quote": "Rapid uptake of AI-ready data centers, the migration from single- to three-phase rack power, and enterprise-wide energy-efficiency mandates are amplifying demand for intelligent, networked power distribution"
  }
 ]
}

